import os
import secrets
from urllib.parse import urlencode
import requests
from flask import Flask, redirect, url_for, session, request, flash

app = Flask(__name__)
app.secret_key = os.environ.get("FLASK_SECRET_KEY", secrets.token_urlsafe(32))

# OpenID Connect Provider Configuration
OIDC_PROVIDER_URL = os.environ.get("OIDC_PROVIDER_URL", "http://localhost:8080/realms/test")
CLIENT_ID = os.environ.get("OIDC_CLIENT_ID", "flask-oidc-client")
CLIENT_SECRET = os.environ.get("OIDC_CLIENT_SECRET", "YOUR_CLIENT_SECRET") # Only needed for response_type=code or token endpoint

# Dynamically fetch OIDC configuration
WELL_KNOWN_CONFIG = {}

def get_oidc_config():
    global WELL_KNOWN_CONFIG
    if not WELL_KNOWN_CONFIG:
        config_url = f"{OIDC_PROVIDER_URL}/.well-known/openid-configuration"
        try:
            response = requests.get(config_url)
            response.raise_for_status()
            WELL_KNOWN_CONFIG = response.json()
        except requests.exceptions.RequestException as e:
            app.logger.error(f"Failed to fetch OIDC configuration from {config_url}: {e}")
            raise RuntimeError(f"Could not fetch OIDC configuration: {e}")
    return WELL_KNOWN_CONFIG

@app.before_first_request
def initialize_oidc_config():
    try:
        get_oidc_config()
    except RuntimeError as e:
        app.logger.error(f"Application startup failed: {e}")
