@app.route('/')
def index():
    if 'id_token' in session:
        return (f"<h1>Welcome, authenticated user!</h1>"
                f"<p>ID Token: {session['id_token']}</p>"
                f"<p><a href=\"{url_for('logout')}\">Logout</a></p>")
    return (f"<h1>Flask OIDC Client</h1>"
            f"<p><a href=\"{url_for('login')}\">Login with OIDC</a></p>")

@app.route('/login')
def login():
    try:
        config = get_oidc_config()
    except RuntimeError:
        flash("OIDC configuration not available. Please check server logs.", "error")
        return redirect(url_for('index'))

    auth_endpoint = config.get('authorization_endpoint')
    if not auth_endpoint:
        flash("Authorization endpoint not found in OIDC configuration.", "error")
        return redirect(url_for('index'))

    redirect_uri = url_for('oidc_callback', _external=True)

    params = {
        'client_id': CLIENT_ID,
        'redirect_uri': redirect_uri,
        'scope': 'openid',
        'response_type': 'id_token',
        # 'nonce': secrets.token_urlsafe(16) # Skipping nonce for now as per requirement
    }

    auth_url = f"{auth_endpoint}?{urlencode(params)}"
    return redirect(auth_url)

@app.route('/oidc_callback')
def oidc_callback():
    if 'error' in request.args:
        error_description = request.args.get('error_description', 'No description provided.')
        flash(f"Authentication error: {error_description}", "error")
        return redirect(url_for('index'))

    # id_token is typically returned as a fragment in the redirect_uri
    # Flask's request.args only captures query parameters.
    # For fragment parameters, JavaScript would normally be used to extract them.
    # However, since the browser strips the fragment before sending it to the server,
    # we simulate this by assuming a client-side redirection that moves the fragment
