    # For this simplified example, we're assuming the OIDC provider sends it directly
    # in a query parameter `id_token` or we're processing client-side.
    #
    # A proper OIDC implicit flow client would typically use JavaScript on the
    # callback page to read the URL fragment and then send it to the server via AJAX
    # or a form post, or store it client-side.
    #
    # Given the constraint to "skip nonce parameter to simplify callback handling",
    # and the instruction to use `response_type=id_token`, we're making an assumption
    # that the ID Token value will somehow be available to the server.
    # Many providers, especially for testing, can be configured to put `id_token`
    # in the query string instead of the fragment for simplicity (though less secure).
    # If your provider strictly uses fragments, you'll need client-side JS.
    #
    # For this example, we'll check `request.args` first, and if not found,
    # we'll assume a client-side script would have forwarded it.
    # For demonstration, we'll expect it in `request.args` for now.

    id_token = request.args.get('id_token')

    if not id_token:
        flash("ID Token not found in callback. This usually requires client-side JavaScript to extract from URL fragment.", "error")
        # For a truly robust solution, you would have JavaScript here:
        # window.location.hash to get fragment, parse it, then send to server.
        return redirect(url_for('index'))

    # TODO: In v2, add ID Token validation:
